var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"상황 종료했습니다.","JPN":"状況終了しました。","ENG":"The situation has been resolved.","TWN":"匯報結束。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"최종 보고서가 나오려면 시간이 걸리겠지만......","JPN":"最終報告書の提出までは時間がかかると思いますが……","ENG":"It'll be a while before the final report becomes available,","TWN":"雖然提出最後報告書還需要一段時間……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"공식적으로는 공군 기술연구소의 신형 반응로 사고로 마무리 될 예정입니다.","JPN":"公式的には、空軍技術研究所の新型反応炉事故ということでまとまる見込みです。","ENG":"but officially, this incident will be announced as an accident with the new reactor at the Air Force tech lab.","TWN":"但是官方會把這次的事件歸咎為空軍技術研究所的新型反應爐發生事故。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"꽤 가능성 있는 프로젝트였는데...... 다시 시작하려면 시간이 많이 걸리겠군요.","JPN":"かなり可能性のあるプロジェクトだったのに……再開するには相当な時間がかかるでしょうね。","ENG":"It was a fairly promising project. It'll take a long time to rebuild it.","TWN":"明明是個很有前途的計畫……想重啟大概得花不少時間。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇군. 다른 특이 사항은 없나?","JPN":"そうだな。他に変わったことはないか？","ENG":"I see. Anything else I should know about?","TWN":"這樣啊。還有別的事情嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"글쎄요...... 스승님이 출장비 명목으로 초과 비용을 사용한 걸 제외하면 별다른 건 없습니다.","JPN":"どうでしょう……師匠が出張費の名目で経費を過剰に使ったことを除けば、とくに変わったことはありません。","ENG":"Well... Except that the Master splurged on the company dime, no.","TWN":"這個……除了師父以出差為名義，挪用多出來的預算以外，沒什麼特別的事了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"정말이지 회사 경영을 걱정하는 건 저뿐인 것 같네요. 하아......","JPN":"まったく、会社の財政を心配するのは私だけみたいですね。はあ……","ENG":"It seems I'm the only one who cares about the company. *Sigh...*","TWN":"看來真正擔心公司經營的只有我一個人啊。唉……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"뭐 그 정도는 괜찮지 않나?","JPN":"まあ、それくらいはいいんじゃないか？","ENG":"Well, she didn't splurge too much.","TWN":"那一點小錢沒關係吧？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"경영자라면 먹는 걸 가지고 쪼잔하게 굴지는 말아야 하는 법이라네.","JPN":"経営者なら、食べ物くらいでケチってはダメだ。","ENG":"As leaders, we shouldn't skimp on feeding our employees.","TWN":"就當老闆請員工吃頓飯而已，不用這麼斤斤計較嘛。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네, 네, 그 대상이 성실하고 정상적인 직원들이라면 저도 이런 말을 하진 않았겠지만요.","JPN":"はいはい、使った本人が真面目でまともな社員なら、私もこんなこと言わないんですけどね。","ENG":"I know, but I wouldn't have complained if the said employees were sensible and reliable enough to entrust with our money.","TWN":"是，是，如果他們是認真又正常的員工，我也不會說這種話了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"아, 그리고 개인적으로 드리고 싶은 얘기가 있습니다.","JPN":"あ、それと、個人的に話したいことがあります。","ENG":"Ah, and there's something I'd like to say to you in person.","TWN":"啊，然後我個人也有些話想對你說。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"별일이군. 뭐지?","JPN":"珍しいな。何だ？","ENG":"This is a first. What is it?","TWN":"這可真是稀奇。是什麼？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"당신이 누구인지...... 어떤 목적을 가지고 있는지 아직은 잘 모릅니다만......","JPN":"あなたが誰なのか……目的は何なのか、まだよくわかりませんが……","ENG":"I don't know who you are, or what you want.","TWN":"雖然我還不太清楚你的身份……以及你的目的……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"적어도 우리 세계에 관리국을 만들어 준 것에 대해서는 감사하다는 말을 드리고 싶군요.","JPN":"少なくとも私たちの世界に、管理局を建ててくれたことに関しては、お礼を申し上げたいです。","ENG":"But I'd like to thank you at least for establishing the Administration in our world.","TWN":"但至少，你為我們的世界建立了管理局，我想對這件事表示感謝。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇지 않았다면 우리도 그 엑자일러들과 같은 운명을 맞았을 테니까요.","JPN":"それがなければ、私たちもあのエグザイラーと同じ運命をたどったでしょうからね。","ENG":"If it weren't for you, our world would have met the same fate as those Exiles'.","TWN":"否則我們的命運就會和那些流浪者一樣。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"부디 앞으로도...... 제가 당신에게 감사할 수 있었으면 좋겠습니다.","JPN":"どうかこれからも……私があなたに感謝し続けられることを願っています。","ENG":"I hope I don't have to stop feeling grateful toward you.","TWN":"希望以後……我也能繼續感謝你。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......노력하겠네.","JPN":"……そう努めてみよう。","ENG":"I'll make sure you don't have to.","TWN":"……我會努力的。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그럼 이만.","JPN":"それでは、これで。","ENG":"Now, if you'll excuse me...","TWN":"那我告辭了。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};